async function getOrders(userId: number) {
  const user = await db.query('SELECT * FROM users WHERE id = ' + userId);
  const orders = await db.query('SELECT * FROM orders WHERE user_id = ' + userId);

  for (const order of orders) {
    order.items = await db.query('SELECT * FROM items WHERE order_id = ' + order.id);
    for (const item of order.items) {
      item.product = await db.query('SELECT * FROM products WHERE id = ' + item.productId);
    }
  }

  console.log('Orders fetched:', JSON.stringify(orders));
  return orders;
}
